/**
 * Analytics data models for the dashboard feature.
 *
 * These types define the shape of analytics data returned by the
 * AnalyticsService. They are designed to support time-series metrics,
 * summary statistics, and composite dashboard views.
 *
 * Design notes:
 * - TimeSeriesPoint is the atomic unit for all time-based data
 * - MetricSummary wraps a single KPI with its trend information
 * - DashboardData composes multiple summaries into a full dashboard view
 * - AnalyticsQuery controls filtering and time range for all queries
 */

/**
 * Supported metric types for analytics queries.
 */
export type MetricType =
  | 'total-orders'
  | 'total-revenue'
  | 'active-users'
  | 'order-completion-rate';

/**
 * Time granularity for grouping time-series data.
 */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
 * A single data point in a time series.
 */
export interface TimeSeriesPoint {
  /** Start of the time bucket */
  timestamp: Date;
  /** Numeric value for this bucket */
  value: number;
  /** Optional label (e.g., "Mon", "2024-03") */
  label: string;
}

/**
 * Summary of a single metric with current value and trend.
 */
export interface MetricSummary {
  /** Which metric this summary represents */
  metric: MetricType;
  /** Current value of the metric */
  currentValue: number;
  /** Value from the previous period for comparison */
  previousValue: number;
  /** Percentage change from previous to current period */
  changePercent: number;
  /** Whether the trend is positive, negative, or flat */
  trend: 'up' | 'down' | 'flat';
  /** Time-series breakdown of this metric */
  timeSeries: TimeSeriesPoint[];
}

/**
 * Breakdown of orders by status.
 */
export interface OrderStatusBreakdown {
  status: string;
  count: number;
  /** Percentage of total orders */
  percent: number;
}

/**
 * Composite dashboard data combining multiple metrics.
 */
export interface DashboardData {
  /** Summary cards for key metrics */
  summaries: MetricSummary[];
  /** Breakdown of current orders by status */
  ordersByStatus: OrderStatusBreakdown[];
  /** When this dashboard data was generated */
  generatedAt: Date;
  /** The query parameters used to generate this data */
  query: AnalyticsQuery;
}

/**
 * Query parameters for filtering analytics data.
 */
export interface AnalyticsQuery {
  /** Start of the date range (inclusive) */
  startDate: Date;
  /** End of the date range (inclusive) */
  endDate: Date;
  /** Time bucket granularity for time-series data */
  granularity: TimeGranularity;
  /** Optional: filter to a specific user */
  userId?: string;
}

/**
 * Analytics service — aggregates order and user data into dashboard metrics.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user data
 *
 * Architecture notes:
 * - This service is read-only; it does not modify data or emit events.
 * - All aggregation logic lives here, not in repositories.
 * - Methods return pre-computed summaries; callers should not need to
 *   post-process the results.
 * - The service follows the same dependency injection pattern as other
 *   services (constructor params, no direct imports of singletons).
 *
 * Implementation status: STUB — methods return placeholder data.
 * The next developer should replace stub implementations with real
 * aggregation logic using the repository query methods.
 */

import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  OrderStatusBreakdown,
  TimeSeriesPoint,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get the full dashboard data for a given query.
   *
   * Aggregates all key metrics, order breakdowns, and time-series data
   * into a single DashboardData response.
   *
   * Implementation guide for next developer:
   * 1. Fetch all orders within query.startDate..query.endDate
   * 2. Fetch all orders from the previous period (same duration, shifted back)
   * 3. Compute each MetricSummary by comparing current vs previous
   * 4. Group orders by status for the breakdown
   * 5. Build time-series by bucketing orders into query.granularity intervals
   */
  getDashboard(query: AnalyticsQuery): DashboardData {
    this.logger.info(
      `Generating dashboard: ${query.startDate.toISOString()} to ${query.endDate.toISOString()}`,
    );

    const summaries = this.getAllMetricSummaries(query);
    const ordersByStatus = this.getOrderStatusBreakdown(query);

    return {
      summaries,
      ordersByStatus,
      generatedAt: new Date(),
      query,
    };
  }

  /**
   * Get a summary for a single metric type.
   *
   * Implementation guide:
   * - 'total-orders': count orders in the period
   * - 'total-revenue': sum order.total for orders in the period
   * - 'active-users': count distinct userIds from orders in the period
   * - 'order-completion-rate': delivered orders / total orders as percentage
   *
   * For each metric, also compute the previous period value and derive
   * changePercent and trend direction.
   */
  getMetricSummary(metric: MetricType, query: AnalyticsQuery): MetricSummary {
    this.logger.info(`Computing metric: ${metric}`);

    // STUB: Return placeholder data. Replace with real aggregation.
    const timeSeries = this.getTimeSeries(metric, query);

    return {
      metric,
      currentValue: 0,
      previousValue: 0,
      changePercent: 0,
      trend: 'flat',
      timeSeries,
    };
  }

  /**
   * Get time-series data for a specific metric.
   *
   * Implementation guide:
   * 1. Determine bucket boundaries based on query.granularity
   * 2. For each bucket, compute the metric value from orders in that bucket
   * 3. Return one TimeSeriesPoint per bucket with a human-readable label
   *
   * Labels should be formatted based on granularity:
   * - hour: "HH:00"
   * - day: "Mon", "Tue", etc. or "Jan 1"
   * - week: "Week 1", "Week 2"
   * - month: "Jan", "Feb"
   */
  getTimeSeries(metric: MetricType, query: AnalyticsQuery): TimeSeriesPoint[] {
    this.logger.info(
      `Computing time series for ${metric}, granularity: ${query.granularity}`,
    );

    // STUB: Return empty array. Replace with real bucketed aggregation.
    return [];
  }

  /**
   * Get breakdown of orders by status within the query period.
   *
   * Implementation guide:
   * 1. Fetch all orders within query date range
   * 2. Group by status
   * 3. Compute count and percentage for each status
   */
  getOrderStatusBreakdown(query: AnalyticsQuery): OrderStatusBreakdown[] {
    this.logger.info('Computing order status breakdown');

    // STUB: Return empty array. Replace with real grouping.
    return [];
  }

  /**
   * Compute summaries for all supported metric types.
   */
  private getAllMetricSummaries(query: AnalyticsQuery): MetricSummary[] {
    const metricTypes: MetricType[] = [
      'total-orders',
      'total-revenue',
      'active-users',
      'order-completion-rate',
    ];

    return metricTypes.map((metric) => this.getMetricSummary(metric, query));
  }
}

/**
 * Analytics service tests.
 *
 * These tests verify the AnalyticsService stub interface. As the
 * implementation is filled in, update these tests to verify real
 * aggregation logic.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { Database, resetDatabase } from '../src/utils/database.js';
import { UserRepository } from '../src/repositories/user.repository.js';
import { OrderRepository } from '../src/repositories/order.repository.js';
import { AnalyticsService } from '../src/services/analytics.service.js';
import type { AnalyticsQuery, DashboardData, MetricSummary } from '../src/models/analytics.js';

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let analyticsService: AnalyticsService;
  let defaultQuery: AnalyticsQuery;

  beforeEach(() => {
    resetDatabase();
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    analyticsService = new AnalyticsService(orderRepo, userRepo);

    defaultQuery = {
      startDate: new Date('2024-01-01'),
      endDate: new Date('2024-01-31'),
      granularity: 'day',
    };
  });

  describe('getDashboard', () => {
    it('should return a DashboardData object with correct structure', () => {
      const dashboard: DashboardData = analyticsService.getDashboard(defaultQuery);

      expect(dashboard).toBeDefined();
      expect(dashboard.summaries).toBeInstanceOf(Array);
      expect(dashboard.ordersByStatus).toBeInstanceOf(Array);
      expect(dashboard.generatedAt).toBeInstanceOf(Date);
      expect(dashboard.query).toEqual(defaultQuery);
    });

    it('should include summaries for all metric types', () => {
      const dashboard = analyticsService.getDashboard(defaultQuery);

      const metricTypes = dashboard.summaries.map((s) => s.metric);
      expect(metricTypes).toContain('total-orders');
      expect(metricTypes).toContain('total-revenue');
      expect(metricTypes).toContain('active-users');
      expect(metricTypes).toContain('order-completion-rate');
    });
  });

  describe('getMetricSummary', () => {
    it('should return a MetricSummary with correct metric type', () => {
      const summary: MetricSummary = analyticsService.getMetricSummary(
        'total-orders',
        defaultQuery,
      );

      expect(summary.metric).toBe('total-orders');
      expect(typeof summary.currentValue).toBe('number');
      expect(typeof summary.previousValue).toBe('number');
      expect(typeof summary.changePercent).toBe('number');
      expect(['up', 'down', 'flat']).toContain(summary.trend);
      expect(summary.timeSeries).toBeInstanceOf(Array);
    });
  });

  describe('getTimeSeries', () => {
    it('should return an array of TimeSeriesPoints', () => {
      const series = analyticsService.getTimeSeries('total-revenue', defaultQuery);

      expect(series).toBeInstanceOf(Array);
    });
  });

  describe('getOrderStatusBreakdown', () => {
    it('should return an array of OrderStatusBreakdown', () => {
      const breakdown = analyticsService.getOrderStatusBreakdown(defaultQuery);

      expect(breakdown).toBeInstanceOf(Array);
    });
  });
});

